// Validate Ghost webhook HMAC-SHA256 signature
const crypto = require('crypto');
const secret = $env.N8N_GHOST_WEBHOOK_SECRET;

if (!secret) {
  console.warn('N8N_GHOST_WEBHOOK_SECRET not set — webhook is unauthenticated');
  return [{json: $json}];
}

const signature = $request.headers['x-ghost-signature'];
if (!signature) {
  throw new Error('Missing X-Ghost-Signature header — request rejected');
}

// Ghost signature format: "sha256=<hex>, t=<timestamp>"
const sigMatch = signature.match(/sha256=([a-f0-9]+)/);
if (!sigMatch) {
  throw new Error('Invalid X-Ghost-Signature format');
}

const body = $request.rawBody;
const expected = crypto.createHmac('sha256', secret).update(body).digest('hex');

if (!crypto.timingSafeEqual(Buffer.from(sigMatch[1], 'hex'), Buffer.from(expected, 'hex'))) {
  throw new Error('X-Ghost-Signature validation failed — request rejected');
}

return [{json: $json}];

// Extract Ghost webhook payload
const data = $input.first().json;

// Handle manual trigger or empty payload
if (!data || Object.keys(data).length === 0) {
  throw new Error('Webhook triggered with no data. If testing manually, ensure you have provided a sample Ghost payload.');
}

// Ghost 5.x Structure: { "post": { "current": { ... }, "previous": { ... } } }
let post = data.post?.current || data.current || data.post || data.body?.post?.current || data.body?.post || data;
let previous = data.post?.previous || data.previous || data.body?.post?.previous;

if (!post || !post.id || !post.url) {
  console.error('Payload Structure Error. Keys found:', Object.keys(data).join(', '));
  if (data.post) console.error('Post keys:', Object.keys(data.post).join(', '));
  throw new Error(`Ghost webhook payload missing post.current.id or url. Found keys: ${Object.keys(data).join(', ')}`);
}

// Post-processing and status check
post.slug = post.slug || `post-${post.id}`;
post.title = post.title || 'Untitled Post';

// Process if published or updated
const status = post.status?.toLowerCase();
if (status && status !== 'published' && status !== 'updated') {
  return [{ json: { skip: true, reason: `Post status is '${status}' (expected published or updated)` } }];      
}

// Helper to remove audio player from html/lexical for comparison
const stripAudioPlayer = (str) => {
    if (!str) return '';
    if (typeof str !== 'string') str = JSON.stringify(str);
    return str.replace(/<!--kg-card-begin: html-->[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<!--kg-card-end: html-->/gi, '')
              .replace(/<figure[^>]*>[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<\/figure>/gi, '')
              .replace(/<div[^>]*id=["']gn-audio-embed["'][^>]*>[\s\S]*?<\/div>/gi, '')
              .replace(/Listen to article/gi, '')
              .replace(/Skip to content/gi, '');
};

// Check if audio already exists
const currentHtml = post.html || '';
const currentLexical = post.lexical || '';
const hasAudio = stripAudioPlayer(currentHtml).length < currentHtml.length - 50 ||
                 stripAudioPlayer(currentLexical).length < currentLexical.length - 50;

if (hasAudio) {
  return [{ json: { skip: true, reason: 'Post already has audio embed' } }];
}

// Extract hostname from post URL for multi-site routing
// n8n's vm2 sandbox doesn't expose the global URL constructor — 
// parse hostname with a regex.
const parseHostname = (u) => !u ? '' : String(u).replace(/^https?:\/\//, '').replace(/\/.*$/, '').replace(/:\d+$/, '');
const hostname = parseHostname(post.url) || 'unknown';

// Generate job ID: {siteSlug}-pid-{postId}-{slug}-{timestamp}
// Resolve siteSlug to canonical 'site1'/'site2' for callback routing
const site1Url = $env.GHOST_SITE1_URL || '';
const site2Url = $env.GHOST_SITE2_URL || '';
const site1Hostname = parseHostname(site1Url);
const site2Hostname = parseHostname(site2Url);
let siteSlug;
if (site1Hostname && hostname.includes(site1Hostname)) {
  siteSlug = 'site1';
} else if (site2Hostname && hostname.includes(site2Hostname)) {
  siteSlug = 'site2';
} else {
  siteSlug = hostname.replace(/\./g, '-');
}
const timestamp = Date.now();
const generatedJobId = `${siteSlug}-pid-${post.id}-${post.slug}-${timestamp}`;
// Honour caller-supplied backfill_job_id (used by scripts/backfill-audio.*
// to produce a deterministic ID it can poll for); real Ghost webhooks fall
// through to the timestamped generator above.
const jobId = (data.backfill_job_id || generatedJobId).substring(0, 200);

// storageSlug is hostname-with-dashes, used by the TTS service to
// organise uploads under audio/articles/<storageSlug>/. Distinct from
// siteSlug, which stays as the canonical 'site1'/'site2' enum so the
// callback's admin-API key lookup keeps working.
const storageSlug = hostname.replace(/\./g, '-');

return [{
  json: {
    skip: false,
    postId: post.id,
    postSlug: post.slug,
    postTitle: post.title,
    postUrl: post.url,
    hostname: hostname,
    siteSlug: siteSlug,
    storageSlug: storageSlug,
    jobId: jobId,
    publishedAt: post.published_at || post.created_at
  }
}];

const item = $input.first().json;
const post = item.posts?.[0];

if (!post) {
  throw new Error('Could not fetch article from Ghost API');
}

// Clean up the plaintext
let text = post.plaintext || '';
text = text.replace(/\n{3,}/g, '\n\n').trim();

if (!text) {
  throw new Error('Post has no plaintext content - cannot generate audio');
}

// Get metadata from previous node
const meta = $('Extract Post Metadata').first().json;

return [{
  json: {
    jobId: meta.jobId,
    siteSlug: meta.siteSlug,
    postTitle: post.title,
    postSlug: post.slug,
    articleText: text,
    wordCount: text.split(/\s+/).length,
    ttsAuthHeader: 'Bearer ' + $env.TTS_API_KEY
  }
}];

const result = $input.first().json;
console.log('TTS Job submitted:', result);
if (result.error || result.detail) {
  throw new Error('TTS service rejected job: ' + (result.error || result.detail));
}
return [{ json: { success: true, ...result } }];
